const setData = $('SET Normalize Input').first().json;
const briefRows = $('SUPABASE Get Brief').all().map(i => i.json).filter(x => x && x.id && x.brand_id === setData.brand_id);
const smbRow = $('SUPABASE Get SocialMediaBios').first().json;
const profileRow = $('SUPABASE Get Brand Profile').first().json;

// Pick latest brief with status=ready for THIS brand_id (sorted DESC by created_at)
const readyBriefs = briefRows.filter(b => b.status === 'ready').sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
const brief = readyBriefs[0] || briefRows.sort((a, b) => new Date(b.created_at) - new Date(a.created_at))[0];

if (!brief || !brief.id) {
  throw new Error('No hay un brief disponible para esta marca. Coré WF-06 (Generate Brief) primero.');
}
if (brief.brand_id !== setData.brand_id) {
  throw new Error(`BUG: brief brand_id (${brief.brand_id}) does not match request brand_id (${setData.brand_id}). Aborting to avoid cross-brand contamination.`);
}

const channel = (setData.channel_override && String(setData.channel_override).trim()) || brief.channel || 'LinkedIn';
const verticals = Array.isArray(setData.verticals) ? setData.verticals : [];

// brief.brief_json puede venir como string o object
let briefJson = brief.brief_json;
if (typeof briefJson === 'string') {
  try { briefJson = JSON.parse(briefJson); } catch (e) { /* leave as-is */ }
}

// SocialMediaBios per-channel
let analysis = smbRow?.analysis_json || {};
if (typeof analysis === 'string') {
  try { analysis = JSON.parse(analysis); } catch (e) { analysis = {}; }
}
const voiceRules  = analysis.voiceRules || { always: [], never: [] };
const tone        = analysis.tone || null;
const toneSummary = analysis.toneSummary || '';
const topPosts    = Array.isArray(analysis.topPosts) ? analysis.topPosts.slice(0, 3).map(p => ({ format: p.format, snippet: (p.text || p.snippet || '').slice(0, 200), why_it_worked: p.whyItWorked || null })) : [];

// Brand profile
let profile = profileRow?.data_json || {};
if (typeof profile === 'string') {
  try { profile = JSON.parse(profile); } catch (e) { profile = {}; }
}
const identity = profile.identity || {};
const services = Array.isArray(profile.services) ? profile.services : [];
const toneByChannel = Array.isArray(profile.tone_by_channel) ? profile.tone_by_channel : [];
const contentSamples = Array.isArray(profile.content_samples) ? profile.content_samples : [];
const toneForChannel = toneByChannel.find(t => (t.channel || '').toLowerCase() === channel.toLowerCase()) || null;
const samplesForChannel = contentSamples.filter(s => (s.channel || '').toLowerCase() === channel.toLowerCase()).slice(0, 3);

// Competitor videos (optional)
let competitorVideos = [];
try {
  competitorVideos = $('Fetch Competitor Videos').all().map(i => i.json).filter(x => x && x.link);
  competitorVideos.sort((a, b) => (b.views || 0) - (a.views || 0));
  competitorVideos = competitorVideos.slice(0, 10);
} catch(e) { competitorVideos = []; }

// Extract competitor hooks from analysis + concepts
const competitorHooks = [];
competitorVideos.forEach(v => {
  if (v.analysis) {
    const visualMatch = v.analysis.match(/\*\*VISUAL[^:]*:\*\*\s*(.+?)(?:\n|$)/i);
    if (visualMatch && visualMatch[1].length > 10) {
      competitorHooks.push({ text: visualMatch[1].trim(), source: v.competitor_name || v.creator, platform: v.platform || 'instagram', views: v.views || 0, type: 'visual_hook' });
    }
    const spokenMatch = v.analysis.match(/\*\*SPOKEN[^:]*:\*\*[^"]*"([^"]{15,150})"/);
    if (spokenMatch) {
      competitorHooks.push({ text: spokenMatch[1].trim(), source: v.competitor_name || v.creator, platform: v.platform || 'instagram', views: v.views || 0, type: 'spoken_hook' });
    }
  }
  if (v.new_concepts) {
    const spokenMatches = [...String(v.new_concepts).matchAll(/\*\*SPOKEN[^:]*:\*\*[^"]*"([^"]{15,150})"/g)];
    spokenMatches.slice(0, 2).forEach(m => {
      competitorHooks.push({ text: m[1].trim(), source: v.competitor_name || v.creator, platform: v.platform || 'instagram', views: v.views || 0, type: 'claude_concept' });
    });
  }
});
competitorHooks.sort((a, b) => (b.views || 0) - (a.views || 0));
const topCompetitorHooks = competitorHooks.slice(0, 8);

const CHANNEL_STYLE = {
  Instagram: {
    format: 'Instagram Reel caption + carousel-friendly',
    length: '40-80 words. Max 4 short paragraphs. Hook in first line. Caption in Spanish for LATAM.',
    rules: ['Emoji ocasional sin abusar', 'No hashtags al inicio del caption', 'Termina con pregunta o CTA "guardalo" / "comentame"'],
  },
  TikTok: {
    format: 'TikTok video hook + on-screen caption',
    length: 'Ultra corto: 1-3 frases que sirvan como gancho hablado en 30-60s.',
    rules: ['Pattern interrupt en frame 1', 'Claim concreto con número o comparación', 'CTA "comentame X" o "mirá hasta el final"'],
  },
  LinkedIn: {
    format: 'LinkedIn long-form post (Spanish)',
    length: '150-280 palabras. Párrafos cortos (1-3 líneas). Hook con observación operativa relevante.',
    rules: ['Sin hype words', 'Tono consultivo, operator-first', 'CTA hacia comentario o DM'],
  },
};
const channelStyle = CHANNEL_STYLE[channel] || CHANNEL_STYLE.LinkedIn;

return [{
  json: {
    brand_id: setData.brand_id,
    brief_id: brief.id,
    channel,
    persona: brief.persona,
    verticals,
    draft_input: {
      identity: {
        company_name: identity.company_name || 'SWL Consulting',
        tagline: identity.tagline || '',
        mission: identity.mission || '',
        industry: identity.industry || '',
      },
      services,
      brief: briefJson,
      brand_voice_rules: voiceRules,
      tone_dimensions: tone,
      tone_summary: toneSummary,
      tone_by_channel: toneForChannel,
      own_top_posts: topPosts,
      content_samples_for_channel: samplesForChannel,
      competitor_hooks: topCompetitorHooks,
      target_channel: channel,
      target_persona: brief.persona,
      verticals,
      channel_style: channelStyle,
    }
  }
}];

