const aiOutput = $input.first().json;
const ctx = $('CODE Build Draft Prompt').first().json;

const content = aiOutput.output?.[0]?.content?.[0]?.text
             ?? aiOutput.choices?.[0]?.message?.content
             ?? aiOutput.text
             ?? aiOutput;

let draft = (typeof content === 'string') ? JSON.parse(content) : content;
if (draft.draft) draft = draft.draft;

return [{
  json: {
    brand_id: ctx.brand_id,
    brief_id: ctx.brief_id,
    title: draft.title,
    draft_text: draft.draft_text,
    qa_input: {
      draft: draft,
      brand_voice_rules: ctx.draft_input.brand_voice_rules,
      tone_dimensions: ctx.draft_input.tone_dimensions,
      target_persona: ctx.draft_input.target_persona
    }
  }
}];

const qaOutput = $input.first().json;
const draftCtx = $('CODE Parse Draft').first().json;

const content = qaOutput.output?.[0]?.content?.[0]?.text
             ?? qaOutput.choices?.[0]?.message?.content
             ?? qaOutput.text
             ?? qaOutput;

let qa = (typeof content === 'string') ? JSON.parse(content) : content;

const score = Number(qa.final_score) || 0;
const status = score >= 70 ? 'draft' : 'qa_failed';
const passQA = score >= 70;

return [{
  json: {
    brand_id: draftCtx.brand_id,
    brief_id: draftCtx.brief_id,
    draft_type: 'social_post',
    title: draftCtx.title,
    draft_text: draftCtx.draft_text,
    qa_json: qa,
    status: status,
    pass_qa: passQA
  }
}];
